package com.treeeducation.ioas.lead; import com.treeeducation.ioas.audit.*;import com.treeeducation.ioas.auth.UserPrincipal;import com.treeeducation.ioas.common.BusinessException;import com.treeeducation.ioas.media.assetfile.AssetFileRepository;import com.treeeducation.ioas.media.contentpackage.*;import com.treeeducation.ioas.task.*;import org.springframework.data.domain.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.time.Instant; /** Lead application service. */ @Service public class LeadService{private final LeadRepository repo;private final ContentPackageRepository packages;private final AssetFileRepository files;private final TaskRepository tasks;private final AuditLogRepository audits; public LeadService(LeadRepository repo,ContentPackageRepository packages,AssetFileRepository files,TaskRepository tasks,AuditLogRepository audits){this.repo=repo;this.packages=packages;this.files=files;this.tasks=tasks;this.audits=audits;} @Transactional public Lead create(LeadDtos.CreateRequest r,UserPrincipal p){var cp=packages.findById(r.packageId()).orElseThrow(()->BusinessException.notFound("主题包不存在"));var af=files.findById(r.assetFileId()).orElseThrow(()->BusinessException.notFound("文件不存在"));if(!af.getPackageId().equals(r.packageId()))throw BusinessException.badRequest("文件不属于所选主题包");Lead l=new Lead();l.setPackageId(r.packageId());l.setAssetFileId(r.assetFileId());l.setOperatorId(r.operatorId());l.setCustomerName(r.customerName());l.setPhone(r.phone());l.setRemark(r.remark());l.setCreatedBy(p.id());l=repo.save(l);cp.setLeadCount((int)repo.countByPackageId(cp.getId()));Task t=new Task();t.setType(TaskType.operator);t.setTitle("跟进线索："+l.getCustomerName());t.setPackageId(l.getPackageId());t.setAssetFileId(l.getAssetFileId());t.setLeadId(l.getId());t.setAssigneeId(l.getOperatorId());tasks.save(t);audit(AuditAction.create_lead,"lead",l.getId(),p.id(),l.getCustomerName());return l;} public Page<LeadDtos.Response> list(Long packageId,Pageable pageable){return (packageId==null?repo.findAll(pageable):repo.findByPackageId(packageId,pageable)).map(LeadDtos::of);} public Lead get(Long id){return repo.findById(id).orElseThrow(()->BusinessException.notFound("线索不存在"));} @Transactional public Lead updateStatus(Long id,LeadStatus status){Lead l=get(id);l.setStatus(status);l.setUpdatedAt(Instant.now());return l;} private void audit(AuditAction a,String t,Long tid,Long actor,String d){AuditLog log=new AuditLog();log.setAction(a);log.setTargetType(t);log.setTargetId(tid);log.setActorId(actor);log.setDetail(d);audits.save(log);} }
